// Header
UPROPERTY(ReplicatedUsing = OnRep_Health)
float Health = 100.f;

UFUNCTION()
void OnRep_Health();

// Source
void AMyChar::GetLifetimeReplicatedProps(TArray<FLifetimeProperty>& OutLifetimeProps) const {
    Super::GetLifetimeReplicatedProps(OutLifetimeProps);
    DOREPLIFETIME(AMyChar, Health);
    // Or with condition:
    // DOREPLIFETIME_CONDITION(AMyChar, Health, COND_OwnerOnly);
}

void AMyChar::OnRep_Health() {
    // Called on clients when Health changes
    UpdateHealthBar();
}

// Server RPC - client sends fire request to server
UFUNCTION(Server, Reliable, WithValidation)
void ServerFire(FVector Origin, FVector Direction);

bool AMyChar::ServerFire_Validate(FVector Origin, FVector Direction) {
    return Direction.IsNormalized(); // Anti-cheat
}
void AMyChar::ServerFire_Implementation(FVector Origin, FVector Direction) {
    // Server spawns projectile, applies damage
    SpawnProjectile(Origin, Direction);
}

// Multicast - everyone sees the effect
UFUNCTION(NetMulticast, Unreliable)
void MulticastPlayFireEffect();

void AMyChar::MulticastPlayFireEffect_Implementation() {
    PlayMuzzleFlash();
    PlayFireSound();
}
